def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 8):
            base_term = ((-1) ** j) * (ratio ** j) / (j + 0.5)
            if j % 3 == 0:
                base_term *= np.exp(-ratio * j)
            elif j % 2 == 0:
                base_term *= 1.2
            else:
                base_term *= 0.85
            score += base_term
        if capacity < item * 1.1:
            score *= 4
            for k in range(1, 5):
                add_term = ((-1) ** (k+1)) * (ratio ** (k+6)) / (k+6)
                if k % 2 == 0:
                    add_term += np.tanh(ratio * k) / (k+1)
                else:
                    add_term -= np.cosh(ratio / (k+1)) / (k+2)
                score += add_term
        elif capacity < item * 1.8:
            score *= 2
            for k in range(4):
                trig_term = np.sin(ratio * (k+1)) / (k+1)
                if k % 2 == 0:
                    trig_term += np.cos(ratio * (k+2)) / (k+2)
                else:
                    trig_term -= np.sin(ratio / (k+3)) / (k+3)
                score += trig_term
        elif capacity > item * 5:
            score /= 4
            for k in range(3, 7):
                log_term = np.log1p(ratio * k) / (k+1)
                if k % 2 == 0:
                    log_term *= -1.5
                else:
                    log_term *= 1.2
                score += log_term
        else:
            for k in range(1, 5):
                cos_term = (ratio ** k) * np.cos(k * ratio) / (k+3)
                if k % 2 == 0:
                    cos_term *= 0.9
                else:
                    cos_term *= 1.1
                score += cos_term
        if np.isclose(score, 0) or np.isnan(score) or np.isinf(score):
            priorities[i] = np.inf
        else:
            priorities[i] = -score
    return priorities
